import anthropic, json, re
from dataclasses import dataclass

client = anthropic.Anthropic()

@dataclass
class Receipt:
    raw: str
    expected: dict

RECEIPTS = [
    Receipt(
        raw="Starbucks #1234\nDate: 2024-03-15\nLatte x2 $9.50\nMuffin $3.25\nTax $1.02\nTotal: $13.77\nCard: Visa ****4521",
        expected={"vendor": "Starbucks", "date": "2024-03-15", "total": 13.77, "payment_method": "Visa"},
    ),
    Receipt(
        raw="Amazon.com\nOrder 114-1234567\nItem: USB Cable $12.99\nShipping: $0.00\nOrder Total: $12.99\nPaid with: Mastercard",
        expected={"vendor": "Amazon.com", "date": None, "total": 12.99, "payment_method": "Mastercard"},
    ),
    Receipt(
        raw="WHOLE FOODS MARKET\n03/16/2024\nOrganic apples 2lb @ $2.99/lb = $5.98\nAlmond milk $4.49\nTotal $10.47 AMEX",
        expected={"vendor": "Whole Foods Market", "date": "2024-03-16", "total": 10.47, "payment_method": "AMEX"},
    ),
]

def field_f1(predicted: dict, expected: dict) -> float:
    fields = ["vendor", "date", "total", "payment_method"]
    matches = sum(
        1 for f in fields
        if (expected.get(f) is None and predicted.get(f) is None)
        or (expected.get(f) is not None and predicted.get(f) is not None and (
            expected[f].lower() in str(predicted[f]).lower()
            if isinstance(expected[f], str)
            else abs(float(predicted.get(f, 0)) - float(expected[f])) < 0.02
        ))
    )
    return matches / len(fields)

def eval_extraction_prompt(system_prompt: str) -> float:
    total = 0.0
    for receipt in RECEIPTS:
        try:
            resp = client.messages.create(
                model="claude-sonnet-4-5", max_tokens=256,
                system=system_prompt,
                messages=[{"role": "user", "content": receipt.raw}],
            )
            m = re.search(r"\{.*\}", resp.content[0].text, re.DOTALL)
            pred = json.loads(m.group()) if m else {}
        except Exception:
            pred = {}
        total += field_f1(pred, receipt.expected)
    return total / len(RECEIPTS)

EXTRACT_META = """
Write {n} system prompts instructing an LLM to extract fields from a purchase receipt
and return them as JSON: {{"vendor": str|null, "date": "YYYY-MM-DD"|null, "total": float|null,
"payment_method": str|null}}. Handle missing fields with null. Return ONLY the JSON.
{history}
Number prompts: PROMPT 1:, PROMPT 2:, PROMPT 3:
"""

leaderboard = []
for iteration in range(2):
    history = ""
    if leaderboard:
        best = sorted(leaderboard, key=lambda x: -x["score"])
        history = "PREVIOUS (do better):\n" + "\n".join(
            f"  F1={r['score']:.2f}: {r['prompt'][:80]}..." for r in best
        )
    meta_resp = client.messages.create(
        model="claude-sonnet-4-5", max_tokens=1024,
        messages=[{"role": "user", "content": EXTRACT_META.format(n=3, history=history)}],
    )
    candidates = [c.strip() for c in re.split(r"PROMPT\s+\d+:", meta_resp.content[0].text, re.IGNORECASE) if c.strip()][:3]
    for i, cand in enumerate(candidates):
        score = eval_extraction_prompt(cand)
        leaderboard.append({"prompt": cand, "score": score})
        print(f"Iteration {iteration+1} Candidate {i+1}: F1={score:.3f}")

best = max(leaderboard, key=lambda x: x["score"])
print(f"\nBest F1={best['score']:.3f}\n{best['prompt']}")

# WRONG — free-form response leads to unparseable output
resp = client.messages.create(
    model="claude-sonnet-4-5", max_tokens=2048,
    messages=[{"role": "user", "content": meta_prompt}],  # no format constraint
)
# Now requires a brittle regex to extract the prompts

# RIGHT — use tool-calling for guaranteed structure
tools = [{
    "name": "submit_prompts",
    "description": "Submit the generated candidate prompts",
    "input_schema": {
        "type": "object",
        "properties": {
            "candidates": {
                "type": "array",
                "items": {"type": "string"},
                "minItems": 3,
                "maxItems": 5,
            }
        },
        "required": ["candidates"],
    },
}]
resp = client.messages.create(
    model="claude-sonnet-4-5", max_tokens=2048,
    tools=tools,
    tool_choice={"type": "auto"},
    messages=[{"role": "user", "content": meta_prompt}],
)
for block in resp.content:
    if block.type == "tool_use" and block.name == "submit_prompts":
        candidates = block.input["candidates"]
        break

import json, pathlib

CHECKPOINT = pathlib.Path("optimizer_checkpoint.json")

def save_checkpoint(leaderboard: list[dict], completed_iteration: int) -> None:
    CHECKPOINT.write_text(json.dumps({
        "leaderboard": leaderboard,
        "last_completed_iteration": completed_iteration,
    }, indent=2))

def load_checkpoint() -> dict | None:
    return json.loads(CHECKPOINT.read_text()) if CHECKPOINT.exists() else None

def optimize_with_checkpointing(n_candidates: int = 5, n_iterations: int = 5) -> dict:
    """Resume from checkpoint if an earlier run was interrupted."""
    state = load_checkpoint()
    leaderboard: list[dict] = state["leaderboard"] if state else []
    start_t = state["last_completed_iteration"] + 1 if state else 0

    for t in range(start_t, n_iterations):
        candidates = generate_candidates(leaderboard)  # your generation function
        for candidate in candidates:
            score = evaluate_prompt(candidate, VALIDATION_SET)  # your evaluation function
            leaderboard.append({"prompt": candidate, "score": score})
        save_checkpoint(leaderboard, t)
        best = max(r["score"] for r in leaderboard)
        print(f"Iteration {t + 1} complete. Best so far: {best:.3f}")

    return max(leaderboard, key=lambda x: x["score"])
